SELECT COUNT(*) AS talk_count
FROM talks
WHERE conference_id = (SELECT conference_id FROM conferences WHERE conference_name = 'Data Science Summit');

SELECT COUNT(talk_id) AS total_talks
FROM talks
WHERE conference_id = 1;

SELECT title 
FROM talks 
ORDER BY day, title;

SELECT title
FROM talks
WHERE room_id = 0;

SELECT COUNT(attendee_id) AS total_attendees
FROM attendees
WHERE conference_id = 1;

SELECT speaker_name
FROM speakers
WHERE speaker_id IN (
  SELECT DISTINCT speaker_id
  FROM talk_speakers
);
